#!/usr/bin/env bash
# Auto-generated by pad4_featurize_v18.0
set -euo pipefail

SPLIT_BASE="/home/nidhal/PAD4_BENCH/data/splits"
OUTPUT_BASE="/home/nidhal/PAD4_BENCH/features_v18"
CACHE_DIR="/home/nidhal/PAD4_BENCH/features_v18/.cache_mordred"
SCRIPT="$(cd "$(dirname "$0")" && pwd)/pad4_featurize_v18_0.py"

# Each entry: "task strategy"
INVOCATIONS=(
    "regression cliff_aware"
    "regression confirmed"
    "regression lead_opt"
    "regression random"
    "regression scaffold"
    "regression similarity"
    "classification cliff_aware"
    "classification confirmed"
    "classification lead_opt"
    "classification random"
    "classification scaffold"
    "classification similarity"
)

for entry in "${INVOCATIONS[@]}"; do
    read -r task strategy <<< "$entry"
    split_dir="${SPLIT_BASE}/${task}/${strategy}"
    out_dir="${OUTPUT_BASE}/${task}/${strategy}"
    if [ ! -d "$split_dir" ]; then
        echo "ERROR: $split_dir does not exist" >&2
        exit 1
    fi
    echo "=== Processing: ${task}/${strategy} ==="
    python "$SCRIPT" \
        --split_dir "$split_dir" \
        --output_dir "$out_dir" \
        --cache_dir "${CACHE_DIR}" \
        --task auto \
        --test_filename test_locked.csv \
        --variants full fingerprints physchem mordred fragments \
        --ad_score_col t1_self_tanimoto \
        --ad_threshold 0.35 \
        --fragment_min_support 0.01 \
        --n_features_linear 120 \
        --n_outer_cv 5 \
        --n_inner_cv 3 \
        --global_stability_min_folds 3 \
        --seed 42
done

echo "All (task, strategy) pairs complete."
